// Normalize the Spark payload and derive routing fields.
// Spark sends: { event_type, severity?, payload: { company_id, factory_id, ... } }
const items = [];
for (const item of $input.all()) {
  const body = item.json.body || item.json;
  const p = body.payload || {};
  const eventType = body.event_type || 'unknown';

  // human-readable message per anomaly type
  let title, detail;
  switch (eventType) {
    case 'price_spike':
      title = '⚠️ Steel price spike';
      detail = `${p.material_type || 'steel'} moved ${p.price_change_pct ?? '?'}% on ${p.date ?? 'latest tick'} (now ${p.steel_price_egypt_egp ?? p.price ?? '?'} EGP).`;
      break;
    case 'low_efficiency':
    case 'line_efficiency_low':
      title = '🔧 Factory efficiency below 70%';
      detail = `${p.facility || p.production_line || 'A line'} is running at ${p.efficiency ?? p.avg_efficiency ?? '?'}%.`;
      break;
    case 'factory_onboarded':
      title = '🏭 New factory unit onboarded';
      detail = `${p.factory_name} (${p.factory_id}) in ${p.governorate}.`;
      break;
    default:
      title = `Alert: ${eventType}`;
      detail = JSON.stringify(p);
  }

  items.push({ json: {
    event_type: eventType,
    company_id: p.company_id || 'UNKNOWN',
    factory_id: p.factory_id || null,
    severity: body.severity || (eventType === 'price_spike' ? 'high' : 'warning'),
    title,
    detail,
    raw: p
  }});
}
return items;
